import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        try {
            const { data, error } = await supabase
                .from('consolidated_transactions')
                .insert(transactions.map(t => ({
                    transaction_date: t.transaction_date,
                    amount: t.amount,
                    description: t.description,
                    type: t.type,
                    pix_key: t.pix_key,
                    source: t.source,
                    user_id: t.user_id,
                    bank_id: t.bank_id,
                    status: 'pending' as const
                })))
                .select();

            if (error) throw error;
            return data || [];
        } catch (e) {
            console.error("[Consolidation:BATCH_INSERT_FAIL]", e);
            return [];
        }
    },

    getExistingTransactionsForDedup: async (userId: string) => {
        try {
            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('transaction_date, amount, description, type, bank_id')
                .eq('user_id', userId)
                .eq('status', 'pending'); // Só comparamos com o que ainda não foi conciliado

            if (error) throw error;
            return data || [];
        } catch (e) {
            console.error("[Consolidation:FETCH_EXISTING_FAIL]", e);
            return [];
        }
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            // Se for bank-id específico, limpa só ele. Se não, limpa tudo do usuário.
            if (bankId && bankId !== 'all') {
                if (bankId === 'gmail-sync') {
                    query = query.is('bank_id', null);
                } else {
                    query = query.eq('bank_id', bankId);
                }
            }

            const { error } = await query;
            if (error) throw error;

            console.log(`[Consolidation] Limpeza remota concluída para: ${bankId || 'todos'}`);
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro crítico na exclusão:", error);
            throw error;
        }
    },

    deleteTransactionById: async (id: string) => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('id', id);
            if (error) throw error;
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro ao deletar transação única:", error);
            throw error;
        }
    },

    getPendingTransactions: async (userId: string) => {
        try {
            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('id, transaction_date, amount, description, type, bank_id')
                .eq('user_id', userId)
                .eq('status', 'pending')
                .order('transaction_date', { ascending: false });

            if (error) throw error;
            return data || [];
        } catch (e) {
            console.error("[Consolidation:FETCH_FAIL]", e);
            return [];
        }
    }
};

import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: any) => {
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);

    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning) return;

        // Permite que chamadas sequenciais ocorram, evitando o travamento da UI 
        // caso o estado isHydrating fique "preso"
        isHydrating.current = true;

        try {
            if (forceClearUI) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
                return;
            }

            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                const bankId = t.bank_id || 'gmail-sync';
                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    cleanedDescription: t.description
                };
                if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                groupedByBank[bankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId === 'gmail-sync' ? 'Sincronização Gmail' : `Lista Viva (Sincronizada)`,
                processedTransactions: txs,
                isRestored: true
            }));

            setBankStatementFile(() => restoredFiles);
            setSelectedBankIds((prev: string[]) => {
                const ids = restoredFiles.map(f => f.bankId);
                return Array.from(new Set([...prev.filter(id => ids.includes(id)), ...ids]));
            });

        } catch (err) {
            console.error("[Lista Viva] Falha na hidratação:", err);
        } finally {
            isHydrating.current = false;
        }
    }, [user, setBankStatementFile, setSelectedBankIds, isCleaning]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate();
        }
    }, [user, hydrate]);

    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };
        const stats = await LaunchService.launchToBank(user.id, bankId, transactions);
        // Pequena espera para garantir que o banco persistiu antes de ler de volta
        await new Promise(resolve => setTimeout(resolve, 500));
        await hydrate();
        return stats;
    }, [user, hydrate]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            // Remove apenas o banco alvo do estado local imediato
            if (bankId && bankId !== 'all') {
                setBankStatementFile((prev: any[]) => prev.filter(f => f.bankId !== bankId));
                setSelectedBankIds((prev: string[]) => prev.filter(id => id !== bankId));
            } else {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            await consolidationService.deletePendingTransactions(user.id, bankId);
            console.log("[Lista Viva] Banco limpo com sucesso.");
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, setBankStatementFile, setSelectedBankIds, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate };
};

import { consolidationService } from './ConsolidationService';
import { Transaction } from '../types';
import { Logger } from './monitoringService';

export const LaunchService = {
    /**
     * Gera Row Hash baseado no conteúdo integral da linha + ID do Banco.
     * Agora normaliza agressivamente espaços e caracteres especiais para evitar duplicatas por formatação.
     */
    computeRowHash: (t: any) => {
        const normalize = (v: any) => String(v || '')
            .trim()
            .toLowerCase()
            .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // Remove acentos
            .replace(/[^a-z0-9]/g, ''); // Mantém APENAS letras e números

        const date = normalize(t.date || t.transaction_date);
        const desc = normalize(t.description);
        const bankId = normalize(t.bank_id);
        // Valor normalizado para 2 casas decimais sem separadores
        const amount = Math.abs(Number(t.amount || 0) * 100).toFixed(0);

        const raw = `${date}|${desc}|${amount}|${bankId}`;

        let hash = 0;
        for (let i = 0; i < raw.length; i++) {
            const char = raw.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; 
        }
        return `h${Math.abs(hash).toString(36)}`;
    },

    async launchToBank(
        userId: string, 
        bankId: string, 
        transactions: Transaction[],
        source: 'file' | 'gmail' = 'file'
    ): Promise<{ added: number, skipped: number, total: number }> {
        if (!userId || transactions.length === 0) {
            return { added: 0, skipped: 0, total: transactions.length };
        }

        const totalReceived = transactions.length;

        // 1. Buscar o que já está no banco
        const existingData = await consolidationService.getExistingTransactionsForDedup(userId);

        // 2. Criar Set de hashes existentes
        const existingHashes = new Set(existingData.map(t => this.computeRowHash(t)));

        // 3. Filtrar apenas os novos baseado no hash normalizado
        const uniqueNewItems = transactions.filter(t => {
            // Para o cálculo do hash de comparação, precisamos injetar o bank_id atual
            const hash = this.computeRowHash({ ...t, bank_id: bankId === 'gmail-sync' ? null : bankId });
            return !existingHashes.has(hash);
        });

        const novosCount = uniqueNewItems.length;
        const ignoradosCount = totalReceived - novosCount;

        if (novosCount === 0) {
            return { added: 0, skipped: ignoradosCount, total: totalReceived };
        }

        const toPersist = uniqueNewItems.map(item => ({
            transaction_date: item.date,
            amount: item.amount,
            description: item.description,
            type: (item.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
            source: source,
            user_id: userId,
            bank_id: bankId === 'gmail-sync' ? null : bankId
        }));

        const data = await consolidationService.addTransactions(toPersist as any);
        const finalAdded = data?.length || 0;

        return { 
            added: finalAdded, 
            skipped: totalReceived - finalAdded, 
            total: totalReceived 
        };
    },

    async clearBankLaunch(userId: string, bankId: string): Promise<void> {
        await consolidationService.deletePendingTransactions(userId, bankId);
    }
};
